// ------------------------------------------------------------------------发送应聘登记表-----------------------------------------------------------------------------------------//
public function pushResumeToOfficial($input)
{
    return OfficialApiLib::sendRequest(
        'official-api/common/record-id-sign',
        [
            'id_sign' => $input['id_sign'],
            'type' => 'resume_info_collect',
            'info' => $input['data_info'],
        ]
    );
}
public function pushProgressOfficial($input)
{
    $review = RecruitmentProgressMd::where(Arr::only($input, ['id_sign', 'password', 'resume_id', 'job_id']))
        ->first();
    $input['review_status'] = $input['review_status'] ?? '初筛中';
    if ($review === null) {
        $job = JobsMd::where('job_id', $input['job_id'])->first();
        if (empty($job)) {
            return [];
        }
        $resume = ResumeMd::where('id', $input['resume_id'])->first();
        if (empty($resume)) {
            return [];
        }
        $expectJobs = $resume->expect_job_ids;
        $apply_time = null;
        foreach ($expectJobs as $expectJob) {
            // 在第四个位置（索引3）追加状态标记
            // 如果已有标记则更新，没有则新增
            if ($expectJob[2] == $input['job_id']) {
                $apply_time = $expectJob[3];
                break;
            }
        }
        $jobName = (empty($job->apply_type) ? '' : ($job->apply_type.'-')).$job->job_name;
        RecruitmentProgressMd::create([
            'id_sign' => $input['id_sign'],
            'password' => $input['password'],

